var src = inputs.Length > 0 ? inputs[0] : null;
if (src == null)
    return new PixelBuffer(context.TileSize, context.TileSize);

var centerX = GetFloat(parameters, "centerX", 0.5f);
var centerY = GetFloat(parameters, "centerY", 0.5f);
var angleDeg = GetFloat(parameters, "angle", 180f);
var radius = GetFloat(parameters, "radius", 0.5f);

var size = src.Width;
var cx = centerX * size;
var cy = centerY * size;
var maxAngle = angleDeg * MathF.PI / 180f;
var effectRadius = radius * size;
if (effectRadius < 1f) effectRadius = 1f;

var result = new PixelBuffer(size, size);

result.ParallelForEachPixel((x, y) =>
{
    var relX = x - cx;
    var relY = y - cy;
    var dist = MathF.Sqrt(relX * relX + relY * relY);

    float sampleX, sampleY;

    if (dist < effectRadius)
    {
        // Normalized distance [0,1] within the effect radius
        var t = dist / effectRadius;
        // Fall off smoothly toward the edge
        var twistAngle = maxAngle * (1f - t) * (1f - t);

        var cosA = MathF.Cos(twistAngle);
        var sinA = MathF.Sin(twistAngle);

        sampleX = cx + relX * cosA - relY * sinA;
        sampleY = cy + relX * sinA + relY * cosA;
    }
    else
    {
        sampleX = x;
        sampleY = y;
    }

    var (r, g, b, a) = src.GetPixelWrapped((int)MathF.Round(sampleX), (int)MathF.Round(sampleY));
    result.SetPixel(x, y, r, g, b, a);
});

return result;
}
